input.command:
kubectl exec -n elasticsearch es-cluster-0 -- curl -s -X PUT "http://localhost:9200/_snapshot/minio-repo" \
  -H "Content-Type: application/json" \
  -d '{
    "type": "s3",
    "settings": {
      "bucket": "es-backups",
      "client": "default",
      "path_style_access": true
    }
  }' 2>&1
